// pdf.js — LES DOCUMENTS GÉNÉRÉS.
// Livrés : fiche individuelle de suivi (livrables 1/5), livret de certification (livrables 2/3).
// À suivre : chevalet (livrable 8), fiche de résolution (6), fiche d'ajournement (7).
// Ce fichier évoluera souvent — une erreur ici ne casse jamais la connexion ni la saisie.
// Dépend de : jsPDF + jspdf-autotable (chargés dans index.html), S, S.data, bilanStagiaire() (app.js).

const ROUGE_SDIS = [200, 16, 46];

// Écusson SDIS 29, encodé une fois pour toutes (extrait des livrables modèles) — évite de
// dépendre d'un fichier image séparé à héberger/uploader : il vit directement dans ce script.
const LOGO_SDIS29 = 'data:image/png;base64,';

function _pdfEnTete(doc, titre, sousTitre) {
  // Largeur dynamique (doc.internal.pageSize) : ce bandeau sert aussi bien aux PDF portrait
  // (fiche de suivi) qu'au livret de certification, désormais en paysage.
  const w = doc.internal.pageSize.getWidth();
  doc.setFillColor(...ROUGE_SDIS);
  doc.rect(0, 0, w, 22, 'F');
  doc.setTextColor(255, 255, 255);
  doc.setFontSize(15);
  doc.text(titre, 14, 12);
  doc.setFontSize(10);
  doc.text(sousTitre, 14, 18);
  doc.setTextColor(30, 30, 30);
}

function _pdfPiedDePage(doc) {
  const nb = doc.internal.getNumberOfPages();
  const auj = new Date().toLocaleDateString('fr-FR');
  for (let i = 1; i <= nb; i++) {
    doc.setPage(i);
    const h = doc.internal.pageSize.getHeight();
    doc.setFontSize(8);
    doc.setTextColor(120, 120, 120);
    doc.text(`Date d'impression : ${auj} — page ${i}/${nb}`, 14, h - 7);
  }
}

// ---------- Fiche individuelle de suivi (livrables 1 & 5) ----------
// Fiche individuelle de suivi (livrables 1/5) — tableau de bord visuel sur le modèle Excel
// fourni par Jérémy : en-tête + photo, un graphique par compétence (auto-éval par critère vs
// formateur, MSP par MSP), courbe de ressenti formateur, tableau mots stagiaire/formateur,
// retours par passage (sujet/commentaire/APP), matrice compétence × MSP, bilan journalier.
// Format paysage comme le livret de certification — même raison : beaucoup de colonnes.
async function genererFicheSuivi(stagiaireId) {
  if (!window.jspdf) return toast('Bibliothèque PDF non chargée', false);
  const s = S.data.stagiaires.find(x => x.id === stagiaireId);
  if (!s) return toast('Stagiaire introuvable', false);
  toast('Génération de la fiche en cours…');

  const { jsPDF } = window.jspdf;
  const doc = new jsPDF({ orientation: 'landscape' });
  const MARGE = 14;
  const CONTENU = doc.internal.pageSize.getWidth() - MARGE * 2;
  const enteteLargeur = MARGE + CONTENU;
  const TITRE = 'Fiche individuelle de suivi';

  const { bilan, nbPassages } = bilanStagiaire(stagiaireId);
  const mesPassages = S.data.passages
    .filter(p => S.data.equipiers.some(e => e.passage_id === p.id && e.stagiaire_id === stagiaireId && e.evalue))
    .sort((a, b) => a.numero - b.numero);
  const mesEvals = pid => S.data.evaluations.find(x => x.passage_id === pid && x.stagiaire_id === stagiaireId);
  const mesAutos = pid => S.data.autoevaluations.find(x => x.passage_id === pid && x.stagiaire_id === stagiaireId);
  const numerosMSP = mesPassages.map(p => p.numero);
  const photo = await _pdfChargerImage(s.photo_url);

  // ---------- En-tête + identité + photo ----------
  _pdfEnTete(doc, TITRE, S.formation.libelle + ' — ' + (S.session.lieu || ''));
  if (photo) { try { doc.addImage(photo.data, 'JPEG', enteteLargeur - 20, 26, 20, 20 * (photo.h / photo.w)); } catch (e) {} }
  let y = 30;
  doc.setFontSize(13);
  doc.setTextColor(30, 30, 30);
  doc.text(s.prenom + ' ' + s.nom, 14, y);
  y += 6;
  doc.setFontSize(9);
  doc.text([
    'CIS de rattachement : ' + (s.cis || '—') + '    ·    Matricule : ' + (s.matricule || '—'),
    'Session : ' + (S.session.date_debut || '?') + ' au ' + (S.session.date_fin || '?') + ' — ' + (S.session.lieu || ''),
    'Responsable pédagogique : ' + (S.session.responsable || '—') + '    ·    ' + nbPassages + ' / ' + S.formation.nb_msp_min + ' mises en situation évaluées.',
  ], 14, y);
  y += 18;

  // Renvoie le nouveau y (30) en plus de le fixer sur la variable englobante : nécessaire pour
  // _pdfBlocGraphesCompetences, qui attend que nouvellePage() lui redonne un y numérique.
  const NOUVELLE_PAGE = () => { doc.addPage(); _pdfEnTete(doc, TITRE, s.prenom + ' ' + s.nom); y = 30; return y; };
  const BAS_PAGE = 185;

  // ---------- Graphiques par compétence (identiques au livret : une courbe par critère
  // d'auto-évaluation + une courbe formateur toujours en orange, légende avec libellé complet) ----------
  doc.setFontSize(6.5);
  doc.setTextColor(120, 120, 120);
  doc.text('Une courbe par critère d\'auto-évaluation (légende avec libellé complet ci-dessous de chaque graphique), plus une courbe formateur (toujours en orange) — échelle 0 à 10 (A+ = 10, A = 7, ECA = 5, NA = 0), n° de MSP en abscisse.', 14, y);
  doc.setTextColor(30, 30, 30);
  y += 4;

  // Bloc factorisé (_pdfBlocGraphesCompetences), partagé à l'identique avec le livret de
  // certification — un correctif de mise en page ne vaut alors que pour une seule copie du code.
  y = _pdfBlocGraphesCompetences(doc, y, MARGE, CONTENU, BAS_PAGE, mesPassages, mesAutos, mesEvals, NOUVELLE_PAGE);

  // ---------- Courbe de ressenti formateur ----------
  if (y > BAS_PAGE - 45) NOUVELLE_PAGE();
  y += 4;
  doc.setFontSize(10);
  doc.setTextColor(30, 30, 30);
  doc.text('Ressenti du formateur au fil des passages (échelle 0 à 10)', 14, y);
  y += 3;
  const ressentisData = mesPassages
    .map(p => { const ev = mesEvals(p.id); return ev && ev.ressenti_formateur != null ? { v: ev.ressenti_formateur * 2, n: p.numero } : null; })
    .filter(d => d != null);
  const ressentis = ressentisData.map(d => d.v);
  const ressentisNumeros = ressentisData.map(d => d.n);
  if (ressentis.length >= 2) {
    _pdfCourbe(doc, 14, y, CONTENU, 30, ressentis, 10, ressentisNumeros);
  } else {
    doc.setDrawColor(200, 200, 200);
    doc.rect(14, y, CONTENU, 30);
    doc.setFontSize(8);
    doc.setTextColor(150, 150, 150);
    doc.text(
      'Pas assez de ressentis formateur renseignés pour tracer une courbe (' + ressentis.length + ' / ' + mesPassages.length + ' passages renseignés).',
      18, y + 15, { maxWidth: CONTENU - 8 }
    );
    doc.setTextColor(30, 30, 30);
  }
  y += 34;

  // ---------- Passage par passage : sujet, mots, commentaire, APP — une seule table fusionnée
  // (plutôt que deux tables séparées « mots » puis « retours ») pour tenir la fiche en 2 pages max. ----------
  if (y > BAS_PAGE - 20) NOUVELLE_PAGE();
  doc.setFontSize(10);
  doc.setTextColor(30, 30, 30);
  doc.text('Passage par passage : sujet, mots, commentaire, APP à proposer', 14, y);
  y += 3;
  const lignesPassages = mesPassages.map(p => {
    const auto = mesAutos(p.id);
    const ev = mesEvals(p.id);
    return [
      p.numero, p.jour, p.sujet || '—',
      auto && auto.ressenti ? auto.ressenti : '—',
      ev && ev.ressenti_mot ? ev.ressenti_mot : '—',
      ev?.commentaire || '—', ev?.app1 || '—', ev?.app2 || '—', ev?.app3 || '—',
    ];
  });
  if (lignesPassages.length) {
    doc.autoTable({
      startY: y,
      head: [['N°', 'Jour', 'Sujet', 'Mot stagiaire', 'Mot formateur', 'Commentaire', 'APP 1', 'APP 2', 'APP 3']],
      body: lignesPassages,
      styles: { fontSize: 6.5, cellPadding: 1.3 },
      headStyles: { fillColor: ROUGE_SDIS },
    });
    y = doc.lastAutoTable.finalY + 8;
  }

  // ---------- Matrice de suivi : note par compétence et par MSP ----------
  if (y > BAS_PAGE - 40) { NOUVELLE_PAGE(); }
  doc.setFontSize(10);
  doc.setTextColor(30, 30, 30);
  doc.text('Matrice de suivi — note par compétence et par MSP', 14, y);
  y += 3;
  const enteteMSP = ['Compétence', ...mesPassages.map(p => 'MSP n°' + p.numero), 'Statut'];
  const corpsMSP = S.formation.competences.map(c => {
    const cellules = mesPassages.map(p => {
      const ev = mesEvals(p.id);
      const n = ev ? ev.notes[c.id] : null;
      return n && n !== 'NE' ? n : (n === 'NE' ? 'N.É.' : '—');
    });
    const b = bilan[c.id];
    return [c.code, ...cellules, _statutFinalCompetence(b.statut, s, c.id)];
  });
  doc.autoTable({
    startY: y,
    head: [enteteMSP],
    body: corpsMSP,
    styles: { fontSize: 7, cellPadding: 1.5, halign: 'center' },
    headStyles: { fillColor: ROUGE_SDIS },
    columnStyles: { 0: { halign: 'left', cellWidth: 14 } },
    didParseCell: (data) => {
      if (data.section === 'body' && data.column.index === enteteMSP.length - 1) {
        const v = data.cell.raw;
        if (v === 'Validé' || v === 'Validé (jury)') data.cell.styles.textColor = [46, 125, 50];
        else if (v === 'Avis du jury') data.cell.styles.textColor = [106, 27, 154];
        else if (v === 'Non acquis' || v === 'Alerte NA' || v === 'Non validé (jury)') data.cell.styles.textColor = [176, 0, 32];
        else if (v === 'En cours') data.cell.styles.textColor = [239, 108, 0];
      }
    },
  });
  y = doc.lastAutoTable.finalY + 8;
  doc.setFontSize(8);
  doc.setTextColor(100, 100, 100);
  doc.text('Règle RIOFE : une compétence à case grisée doit être « acquise » (A ou A+) au moins 2 fois ; une case blanche doit être a minima « en cours d\'acquisition ». Une « non acquisition » en fin de formation entraîne la non-validation.', 14, y, { maxWidth: CONTENU });
  doc.setTextColor(30, 30, 30);
  y += 12;

  // ---------- Bilan journalier (rempli par le stagiaire + remarque formateur) ----------
  if (y > BAS_PAGE - 30) { doc.addPage(); _pdfEnTete(doc, 'Bilan journalier', s.prenom + ' ' + s.nom); y = 28; }
  doc.setFontSize(10);
  doc.text('Bilan de fin de journée', 14, y);
  y += 3;
  const lignesBilan = joursFormation()
    .map(j => ({ j, b: (S.data.bilansJournaliers || []).find(x => x.stagiaire_id === stagiaireId && x.jour === j) }))
    .filter(({ b }) => b && (b.jai_appris || b.jai_besoin || b.je_propose || b.remarque_formateur))
    .map(({ j, b }) => [j, b.jai_appris || '—', b.jai_besoin || '—', b.je_propose || '—', b.remarque_formateur || '—']);
  if (lignesBilan.length) {
    doc.autoTable({
      startY: y,
      head: [['Jour', "J'ai appris et compris", "J'ai besoin (d'approfondir, de compléter, de rechercher…)", 'Je propose', 'Remarque formateur']],
      body: lignesBilan,
      styles: { fontSize: 7.5, cellPadding: 2 },
      headStyles: { fillColor: ROUGE_SDIS },
    });
  } else {
    doc.setFontSize(8);
    doc.setTextColor(150, 150, 150);
    doc.text('Aucun bilan de fin de journée renseigné pour ce stagiaire.', 14, y + 6);
    doc.setTextColor(30, 30, 30);
  }

  _pdfPiedDePage(doc);
  doc.save(`Fiche_suivi_${s.nom}_${s.prenom}.pdf`.replace(/\s+/g, '_'));
  toast('Fiche PDF générée');
}

// ---------- Livret de certification (livrables 2 & 3) ----------
// Charge une image distante (photo du stagiaire) et la renvoie en dataURL, ou null si
// indisponible — une photo manquante/en échec ne doit jamais empêcher la génération du livret.
function _pdfChargerImage(url) {
  return new Promise(resolve => {
    if (!url) return resolve(null);
    const img = new Image();
    img.crossOrigin = 'anonymous';
    img.onload = () => {
      try {
        const c = document.createElement('canvas');
        c.width = img.naturalWidth; c.height = img.naturalHeight;
        c.getContext('2d').drawImage(img, 0, 0);
        resolve({ data: c.toDataURL('image/jpeg', 0.85), w: img.naturalWidth, h: img.naturalHeight });
      } catch (e) { resolve(null); }
    };
    img.onerror = () => resolve(null);
    img.src = url;
  });
}

// Correspondance note formateur → valeur chiffrée 0-10, reprise telle quelle de la formule du
// fichier Excel de traitement fourni par Jérémy (onglet FC : =IF(x="A+",10,IF(x="A",7,IF(x="ECA",5,0))) ).
// NA compte donc 0 comme une case blanche Excel non prévue par la formule ; NE (non évalué)
// est en revanche exclu du graphique plutôt que compté comme 0, pour ne pas fausser la courbe
// avec des MSP où la compétence n'a simplement pas été évaluée.
function _noteFormateurVersChiffre(note) {
  if (note === 'A+') return 10;
  if (note === 'A') return 7;
  if (note === 'ECA') return 5;
  if (note === 'NA') return 0;
  return null;
}

// Couleur imposée pour toute courbe d'évaluation formateur (constante dans tout le livret, pour
// qu'un lecteur habitué au code couleur n'ait pas à re-vérifier la légende à chaque graphique).
const ORANGE_FORMATEUR = [239, 108, 0];
// Palette des courbes d'auto-évaluation stagiaire — une couleur par critère, jamais l'orange
// (réservé au formateur), recyclée si une compétence a plus de critères que de couleurs.
const COULEURS_STAGIAIRE = [[21, 101, 192], [46, 125, 50], [106, 27, 154], [0, 121, 107], [69, 90, 100], [173, 20, 87]];

// Courbe à plusieurs séries sur la même échelle 0-10 — sert à comparer, compétence par
// compétence et MSP par MSP dans l'ordre chronologique de la semaine, l'auto-évaluation du
// stagiaire (une courbe par critère de la compétence, la moyenne seule ne suffit pas à voir le
// détail) et l'évaluation du formateur pour la compétence entière (convertie via
// _noteFormateurVersChiffre). Une valeur manquante sur une série interrompt la ligne à cet
// endroit plutôt que d'interpoler ou de fausser la comparaison.
function _pdfCourbeMultiple(doc, x, y, largeur, hauteur, series, numerosMSP, max) {
  doc.setDrawColor(200, 200, 200);
  doc.rect(x, y, largeur, hauteur);
  doc.setFontSize(5.5);
  doc.setTextColor(150, 150, 150);
  doc.text(String(max), x - 1, y + 3, { align: 'right' });
  doc.text('0', x - 1, y + hauteur, { align: 'right' });
  const n = numerosMSP.length;
  if (n < 2) { doc.setTextColor(30, 30, 30); return; }
  const px = i => x + (i / (n - 1)) * largeur;
  const py = v => y + hauteur - (Math.max(0, Math.min(max, v)) / max) * hauteur;
  for (const s of series) {
    doc.setLineWidth(0.5);
    for (let i = 0; i < s.valeurs.length - 1; i++) {
      if (s.valeurs[i] == null || s.valeurs[i + 1] == null) continue;
      doc.setDrawColor(...s.couleur);
      doc.line(px(i), py(s.valeurs[i]), px(i + 1), py(s.valeurs[i + 1]));
    }
    doc.setFillColor(...s.couleur);
    s.valeurs.forEach((v, i) => { if (v != null) doc.circle(px(i), py(v), 0.8, 'F'); });
    // Repère texte (court) au dernier point valide de chaque courbe : quand les critères
    // d'auto-évaluation divergent, ça permet de voir directement sur le graphique lequel est en
    // retrait, sans devoir recroiser les couleurs avec la légende.
    if (s.court) {
      for (let i = s.valeurs.length - 1; i >= 0; i--) {
        if (s.valeurs[i] == null) continue;
        doc.setFontSize(4);
        doc.setTextColor(...s.couleur);
        doc.text(s.court, px(i) + 1.5, py(s.valeurs[i]) + 1, { align: 'left' });
        break;
      }
    }
  }
  // Juste le numéro (pas « MSP n° ») : les colonnes sont étroites, le préfixe complet
  // provoquerait des chevauchements entre repères successifs.
  doc.setFontSize(4.5);
  doc.setTextColor(120, 120, 120);
  numerosMSP.forEach((num, i) => { if (num != null) doc.text(String(num), px(i), y + hauteur + 3.5, { align: 'center' }); });
  doc.setTextColor(30, 30, 30);
}

// Légende empilée verticalement (carré de couleur + code + LIBELLÉ COMPLET du critère), une
// ligne par série — remplace l'ancienne légende en ligne qui n'affichait que le code (« C1.1 »),
// illisible sans revenir chercher sa signification dans le référentiel p.2. Repliée sur
// plusieurs lignes via splitTextToSize si un libellé est trop long pour la largeur de colonne.
function _pdfLegendeHauteur(doc, largeur, items) {
  doc.setFontSize(5.5);
  let h = 0;
  items.forEach(it => { h += doc.splitTextToSize(it.label, largeur - 5).length * 2.2; });
  return h;
}

function _pdfLegende(doc, x, y, largeur, items) {
  doc.setFontSize(5.5);
  let cy = y;
  items.forEach(it => {
    const lignes = doc.splitTextToSize(it.label, largeur - 5);
    doc.setFillColor(...it.couleur);
    doc.rect(x, cy - 1.8, 1.8, 1.8, 'F');
    doc.setTextColor(...it.couleur);
    lignes.forEach((l, li) => doc.text(l, x + 3, cy + li * 2.2));
    cy += lignes.length * 2.2;
  });
  doc.setTextColor(30, 30, 30);
  return cy;
}

// Bloc de graphiques par compétence (grille 2 colonnes, une courbe par critère d'auto-évaluation
// + une courbe formateur toujours en orange, légende avec libellé complet) — utilisé à
// l'IDENTIQUE par le livret de certification et la fiche individuelle de suivi. Facteur commun
// exprès : un chevauchement de texte a été observé dans les deux documents à la fois (même
// calcul de hauteur de ligne trop juste, dupliqué), corriger ici une seule fois vaut pour les deux
// plutôt que de risquer une nouvelle divergence entre deux copies.
// nouvellePage() doit ouvrir une nouvelle page, redessiner l'en-tête, et renvoyer le nouveau y (30).
function _pdfBlocGraphesCompetences(doc, y, MARGE, CONTENU, BAS_PAGE, mesPassages, mesAutos, mesEvals, nouvellePage) {
  const HAUTEUR_GRAPHE = 12;
  const COL_GAP = 6;
  const COL_LARGEUR = (CONTENU - COL_GAP) / 2;
  const numerosMSP = mesPassages.map(p => p.numero);
  const competencesAvecCriteres = S.formation.competences.filter(c =>
    S.formation.criteres.some(cr => cr.competence_id === c.id));

  for (let idx = 0; idx < competencesAvecCriteres.length; idx += 2) {
    const paire = [competencesAvecCriteres[idx], competencesAvecCriteres[idx + 1]].filter(Boolean);
    doc.setFontSize(6);
    const infosPaire = paire.map(c => {
      const critList = S.formation.criteres.filter(cr => cr.competence_id === c.id).sort((a, b) => a.ordre - b.ordre);
      const seriesStagiaire = critList.map((cr, ci) => {
        const code = c.code + '.' + (ci + 1);
        return {
          label: code + ' — ' + cr.libelle,
          court: code,
          couleur: COULEURS_STAGIAIRE[ci % COULEURS_STAGIAIRE.length],
          valeurs: mesPassages.map(p => { const a = mesAutos(p.id); return a ? a.notes[cr.id] : null; }),
        };
      });
      const serieFormateur = {
        label: 'Formateur',
        court: 'F',
        couleur: ORANGE_FORMATEUR,
        valeurs: mesPassages.map(p => { const ev = mesEvals(p.id); return ev ? _noteFormateurVersChiffre(ev.notes[c.id]) : null; }),
      };
      const toutesSeries = [...seriesStagiaire, serieFormateur];
      return {
        c,
        titreLignes: doc.splitTextToSize(c.code + ' — ' + c.libelle, COL_LARGEUR),
        toutesSeries,
        hLegende: _pdfLegendeHauteur(doc, COL_LARGEUR, toutesSeries),
      };
    });
    const hTitre = Math.max(...infosPaire.map(inf => inf.titreLignes.length)) * 2.8 + 1.2;
    const hLegende = Math.max(...infosPaire.map(inf => inf.hLegende));
    // +10 : marge de sécurité (espace après la légende, décalage + hauteur des repères de n° de
    // MSP sous le graphique, marge avant le titre suivant). Un chevauchement de texte observé sur
    // le livret ET la fiche venait d'un tampon insuffisant ici (+6 seulement) : corrigé une fois
    // pour les deux documents.
    const hRow = hTitre + hLegende + HAUTEUR_GRAPHE + 10;
    if (y > BAS_PAGE - hRow) y = nouvellePage();

    infosPaire.forEach((inf, i) => {
      const x0 = MARGE + i * (COL_LARGEUR + COL_GAP);
      doc.setFontSize(6);
      doc.setTextColor(30, 30, 30);
      inf.titreLignes.forEach((l, li) => doc.text(l, x0, y + li * 2.8));
      const yLegende = y + hTitre;
      const yGraphe = _pdfLegende(doc, x0, yLegende, COL_LARGEUR, inf.toutesSeries) + 1.5;
      _pdfCourbeMultiple(doc, x0, yGraphe, COL_LARGEUR, HAUTEUR_GRAPHE, inf.toutesSeries, numerosMSP, 10);
    });
    y += hRow;
  }
  return y;
}

// Courbe (ligne brisée) pour le ressenti formateur au fil des passages, avec repères d'échelle
// à gauche, valeur chiffrée au-dessus de chaque point et n° de MSP en abscisse (optionnel).
function _pdfCourbe(doc, x, y, largeur, hauteur, valeurs, max, numerosMSP) {
  doc.setDrawColor(200, 200, 200);
  doc.rect(x, y, largeur, hauteur);
  doc.setFontSize(5.5);
  doc.setTextColor(150, 150, 150);
  doc.text(String(max), x - 1, y + 3, { align: 'right' });
  doc.text('0', x - 1, y + hauteur, { align: 'right' });
  if (valeurs.length < 2) return;
  const n = valeurs.length;
  const px = i => x + (i / (n - 1)) * largeur;
  const py = v => y + hauteur - (Math.max(0, Math.min(max, v || 0)) / max) * hauteur;
  doc.setDrawColor(...ROUGE_SDIS);
  doc.setLineWidth(0.5);
  for (let i = 0; i < n - 1; i++) doc.line(px(i), py(valeurs[i]), px(i + 1), py(valeurs[i + 1]));
  doc.setFillColor(...ROUGE_SDIS);
  valeurs.forEach((v, i) => {
    doc.circle(px(i), py(v), 0.8, 'F');
    doc.setFontSize(5.5);
    doc.setTextColor(...ROUGE_SDIS);
    doc.text(String(v), px(i), Math.max(y + 3, py(v) - 2), { align: 'center' });
    if (numerosMSP && numerosMSP[i] != null) {
      doc.setFontSize(5);
      doc.setTextColor(120, 120, 120);
      doc.text('MSP ' + numerosMSP[i], px(i), y + hauteur + 4, { align: 'center' });
    }
  });
  doc.setTextColor(30, 30, 30);
}

async function genererLivretCertification(stagiaireId) {
  if (!window.jspdf) return toast('Bibliothèque PDF non chargée', false);
  const s = S.data.stagiaires.find(x => x.id === stagiaireId);
  if (!s) return toast('Stagiaire introuvable', false);
  toast('Génération du livret en cours…');

  const { jsPDF } = window.jspdf;
  // Format paysage — les tableaux (matrice de validation par MSP, retours par MSP) ont
  // beaucoup de colonnes et respirent mieux en largeur qu'en hauteur.
  const doc = new jsPDF({ orientation: 'landscape' });
  const MARGE = 14;
  const CONTENU = doc.internal.pageSize.getWidth() - MARGE * 2; // largeur utile (269 en A4 paysage)
  const { bilan, nbPassages } = bilanStagiaire(stagiaireId);
  const mesPassages = S.data.passages
    .filter(p => S.data.equipiers.some(e => e.passage_id === p.id && e.stagiaire_id === stagiaireId && e.evalue))
    .sort((a, b) => a.numero - b.numero);
  const mesEvals = pid => S.data.evaluations.find(x => x.passage_id === pid && x.stagiaire_id === stagiaireId);
  const mesAutos = pid => S.data.autoevaluations.find(x => x.passage_id === pid && x.stagiaire_id === stagiaireId);
  const photo = await _pdfChargerImage(s.photo_url);

  // ---------- Page 1 : couverture ----------
  // En-tête façon « cartouche » corporate, sur le modèle du livret original : écusson à
  // gauche, titre du document au centre, case Édition/Révision à droite.
  const enteteLargeur = MARGE + CONTENU;
  const xCorner = enteteLargeur - 35;
  doc.setFillColor(255, 255, 255);
  doc.setDrawColor(...ROUGE_SDIS);
  doc.setLineWidth(0.6);
  doc.rect(10, 10, enteteLargeur - 10, 32);
  doc.line(40, 10, 40, 42);
  doc.line(xCorner, 10, xCorner, 42);
  doc.line(xCorner, 26, enteteLargeur, 26);
  try {
    const lw = 15.4, lh = 24;
    doc.addImage(LOGO_SDIS29, 'PNG', 10 + (30 - lw) / 2, 10 + (32 - lh) / 2, lw, lh);
  } catch (e) { /* écusson non intégrable, on continue sans */ }

  const centreTitre = (40 + xCorner) / 2;
  doc.setTextColor(30, 30, 30);
  doc.setFont(undefined, 'normal');
  doc.setFontSize(9);
  const titreLignes = doc.splitTextToSize('Référentiel Interne d\'Organisation de la Formation et d\'Évaluations', xCorner - 40 - 10);
  let ty = 16;
  titreLignes.forEach(l => { doc.text(l, centreTitre, ty, { align: 'center' }); ty += 4; });
  doc.setFont(undefined, 'italic');
  doc.setFontSize(12);
  doc.text('Livret de Suivi des Compétences', centreTitre, ty + 3, { align: 'center' });
  doc.setFont(undefined, 'normal');
  doc.setFontSize(8);
  doc.text('SDIS 29 — Groupement Formation', centreTitre, ty + 11, { align: 'center' });

  doc.setFontSize(7);
  doc.setTextColor(90, 90, 90);
  doc.text('Édition :', xCorner + 2, 17);
  doc.text(new Date().toLocaleDateString('fr-FR'), xCorner + 2, 21);
  doc.text('Révision :', xCorner + 2, 33);
  doc.text('—', xCorner + 2, 37);
  doc.setTextColor(30, 30, 30);

  let y = 58;
  doc.setFontSize(16);
  doc.text('NOM et PRÉNOM :', 14, y);
  doc.text(s.prenom + ' ' + s.nom, 80, y);
  y += 12;
  doc.text('Matricule :', 14, y);
  doc.text(s.matricule || '—', 80, y);
  y += 12;
  doc.text('Affectation :', 14, y);
  doc.text(s.cis || '—', 80, y);

  if (photo) {
    try {
      const w = 35, h = w * (photo.h / photo.w);
      doc.addImage(photo.data, 'JPEG', enteteLargeur - w, 48, w, h);
    } catch (e) { /* photo non intégrable, on continue sans */ }
  }

  y = 108;
  doc.setFontSize(10);
  doc.text('Domaine d\'activité : ' + esc(S.formation.libelle), 14, y); y += 8;
  doc.text('Stage : ' + esc(S.formation.libelle) + '   du ' + (S.session.date_debut || '?') + ' au ' + (S.session.date_fin || '?') + '   lieu : ' + (S.session.lieu || '—'), 14, y); y += 8;
  doc.text('Responsable de stage : ' + (S.session.responsable || '—') + '        Signature : ______________________', 14, y);

  // ---------- Page 2 : référentiel des compétences ----------
  doc.addPage();
  _pdfEnTete(doc, 'Référentiel des compétences', S.formation.libelle);
  const lignesRef = [];
  for (const c of S.formation.competences) {
    lignesRef.push([{ content: c.code + ' — ' + c.libelle, colSpan: 2, styles: { fillColor: [46, 125, 50], textColor: 255, fontStyle: 'bold' } }]);
    const crit = S.formation.criteres.filter(cr => cr.competence_id === c.id).sort((a, b) => a.ordre - b.ordre);
    crit.forEach((cr, i) => lignesRef.push([c.code + '.' + (i + 1), cr.libelle]));
    if (!crit.length) lignesRef.push(['', { content: '(aucun critère détaillé rattaché)', styles: { textColor: [150, 150, 150] } }]);
  }
  doc.autoTable({
    startY: 28,
    head: [['Code', 'Compétence / critère associé']],
    body: lignesRef,
    styles: { fontSize: 8, cellPadding: 1.5 },
    headStyles: { fillColor: ROUGE_SDIS },
    columnStyles: { 0: { cellWidth: 12 } },
  });

  // ---------- Page 3 : matrice de validation par MSP + signatures ----------
  doc.addPage();
  _pdfEnTete(doc, 'Matrice de validation', s.prenom + ' ' + s.nom);
  const enteteMSP = ['Compétence', ...mesPassages.map(p => 'MSP n°' + p.numero), 'Validation'];
  const corpsMSP = S.formation.competences.map(c => {
    const cellules = mesPassages.map(p => {
      const ev = mesEvals(p.id);
      const n = ev ? ev.notes[c.id] : null;
      return n && n !== 'NE' ? n : (n === 'NE' ? 'N.É.' : '—');
    });
    const b = bilan[c.id];
    return [c.code, ...cellules, _statutFinalCompetence(b.statut, s, c.id)];
  });
  doc.autoTable({
    startY: 28,
    head: [enteteMSP],
    body: corpsMSP,
    styles: { fontSize: 7, cellPadding: 1.5, halign: 'center' },
    headStyles: { fillColor: ROUGE_SDIS },
    columnStyles: { 0: { halign: 'left', cellWidth: 14 } },
    didParseCell: (data) => {
      if (data.section === 'body' && data.column.index === enteteMSP.length - 1) {
        const v = data.cell.raw;
        if (v === 'Validé' || v === 'Validé (jury)') data.cell.styles.textColor = [46, 125, 50];
        else if (v === 'Avis du jury') data.cell.styles.textColor = [106, 27, 154];
        else if (v === 'Non acquis' || v === 'Alerte NA' || v === 'Non validé (jury)') data.cell.styles.textColor = [176, 0, 32];
        else if (v === 'En cours') data.cell.styles.textColor = [239, 108, 0];
      }
    },
  });
  y = doc.lastAutoTable.finalY + 10;
  doc.setFontSize(9);
  doc.text('Plan d\'axes d\'amélioration continue :', 14, y);
  doc.setDrawColor(180, 180, 180);
  doc.rect(14, y + 3, CONTENU, 24);
  y += 34;
  doc.text(nbPassages + ' / ' + S.formation.nb_msp_min + ' mises en situation évaluées.', 14, y);
  y += 12;
  const dec = s.decision_jury === 'valide' ? 'APTE' : s.decision_jury === 'non_valide' ? 'INAPTE' : '— à décider —';
  const couleurDec = s.decision_jury === 'valide' ? [46, 125, 50] : s.decision_jury === 'non_valide' ? [200, 16, 46] : [120, 120, 120];
  doc.setFontSize(10);
  doc.setTextColor(30, 30, 30);
  doc.text('Date : ' + new Date().toLocaleDateString('fr-FR'), 14, y);
  doc.text('Responsable pédagogique : ' + (S.session.responsable || '—'), 14, y + 7);
  // Décision très visible (gros, gras, couleur) — c'est l'information la plus importante de la
  // page pour un lecteur qui la parcourt rapidement.
  doc.text('Décision :', 14, y + 17);
  doc.setFont(undefined, 'bold');
  doc.setFontSize(20);
  doc.setTextColor(...couleurDec);
  doc.text(dec, 42, y + 18);
  doc.setFont(undefined, 'normal');
  doc.setFontSize(10);
  doc.setTextColor(30, 30, 30);
  doc.text('Stagiaire : ' + s.prenom + ' ' + s.nom + '        Signature :', 14, y + 28);

  // ---------- Page 4 : suivi individuel visuel ----------
  // Un graphique par compétence, comparant sur la semaine (une abscisse par MSP, dans l'ordre
  // chronologique) l'auto-évaluation du stagiaire (moyenne de ses critères, déjà sur 0-10) et
  // l'évaluation du formateur pour cette compétence (A+/A/ECA/NA convertie sur la même échelle
  // 0-10, correspondance reprise du fichier Excel de traitement fourni par Jérémy).
  // ⚠ Doit toujours ouvrir une VRAIE nouvelle page avant de redessiner l'en-tête — un bug ici
  // (en-tête redessiné sans addPage()) a provoqué un chevauchement de tout le contenu de la
  // page 4 sur une seule page dans une version précédente.
  const NOUVELLE_PAGE4 = () => { doc.addPage(); _pdfEnTete(doc, 'Tableau récapitulatif de suivi individuel', s.prenom + ' ' + s.nom); y = 30; };
  NOUVELLE_PAGE4();
  if (photo) { try { doc.addImage(photo.data, 'JPEG', enteteLargeur - 20, 26, 20, 20 * (photo.h / photo.w)); } catch (e) {} }
  y = 27;
  doc.setFontSize(6.5);
  doc.setTextColor(120, 120, 120);
  doc.text('Une courbe par critère d\'auto-évaluation (légende avec libellé complet ci-dessous de chaque graphique), plus une courbe formateur (toujours en orange) — échelle 0 à 10 (A+ = 10, A = 7, ECA = 5, NA = 0), n° de MSP en abscisse.', 14, y);
  doc.setTextColor(30, 30, 30);
  y += 4;
  // Deux colonnes, mise en page resserrée pour tenir le plus de compétences possible sur une
  // seule page — bloc factorisé (_pdfBlocGraphesCompetences), partagé avec la fiche individuelle
  // de suivi pour qu'un correctif ne vaille que pour une seule copie du code.
  const BAS_PAGE = 185; // hauteur utile en paysage (page 210mm de haut, marge basse pour le pied de page)
  y = _pdfBlocGraphesCompetences(doc, y, MARGE, CONTENU, BAS_PAGE, mesPassages, mesAutos, mesEvals, () => { NOUVELLE_PAGE4(); return y; });

  // ---- Ressenti stagiaire (mot), au-dessus de la courbe de ressenti formateur : deux tableaux
  // Passage n°/Jour/Ressenti côte à côte (6 colonnes au total) pour utiliser toute la largeur de
  // la page plutôt qu'une longue liste verticale à 3 colonnes, sur le modèle demandé par Jérémy. ----
  if (y > BAS_PAGE - 95) NOUVELLE_PAGE4();
  y += 4;
  doc.setFontSize(10);
  doc.setTextColor(30, 30, 30);
  doc.text('Ressenti du stagiaire au fil des passages (mot)', 14, y);
  y += 3;
  let finRessentiMot = y;
  if (mesPassages.length) {
    const milieu = Math.ceil(mesPassages.length / 2);
    const gauche = mesPassages.slice(0, milieu);
    const droite = mesPassages.slice(milieu);
    const largeurDemi = (CONTENU - 6) / 2;
    const ligneRessenti = p => { const a = mesAutos(p.id); return [p.numero, p.jour, a && a.ressenti ? a.ressenti : '—']; };
    doc.autoTable({
      startY: y,
      margin: { left: 14, right: MARGE + largeurDemi + 6 },
      tableWidth: largeurDemi,
      head: [['Passage n°', 'Jour', 'Ressenti (mot)']],
      body: gauche.map(ligneRessenti),
      styles: { fontSize: 7.5, cellPadding: 1.5 },
      headStyles: { fillColor: ROUGE_SDIS },
    });
    finRessentiMot = doc.lastAutoTable.finalY;
    if (droite.length) {
      doc.autoTable({
        startY: y,
        margin: { left: 14 + largeurDemi + 6 },
        tableWidth: largeurDemi,
        head: [['Passage n°', 'Jour', 'Ressenti (mot)']],
        body: droite.map(ligneRessenti),
        styles: { fontSize: 7.5, cellPadding: 1.5 },
        headStyles: { fillColor: ROUGE_SDIS },
      });
      finRessentiMot = Math.max(finRessentiMot, doc.lastAutoTable.finalY);
    }
  }
  y = finRessentiMot + 8;

  doc.setFontSize(10);
  doc.setTextColor(30, 30, 30);
  doc.text('Ressenti du formateur au fil des passages (échelle 0 à 10)', 14, y);
  y += 3;
  // Ressenti formateur noté sur 0-5 dans l'appli, converti sur 0-10 pour l'échelle du graphique.
  // On garde le n° de MSP associé à chaque valeur pour l'afficher en abscisse (repère lisible
  // plutôt qu'une simple série de points sans contexte).
  const ressentisData = mesPassages
    .map(p => { const ev = mesEvals(p.id); return ev && ev.ressenti_formateur != null ? { v: ev.ressenti_formateur * 2, n: p.numero } : null; })
    .filter(d => d != null);
  const ressentis = ressentisData.map(d => d.v);
  const ressentisNumeros = ressentisData.map(d => d.n);
  if (ressentis.length >= 2) {
    _pdfCourbe(doc, 14, y, CONTENU, 30, ressentis, 10, ressentisNumeros);
  } else {
    // Moins de 2 valeurs : une courbe n'a pas de sens (rien à relier). On l'explique plutôt que
    // de laisser un cadre vide et silencieux, qui laissait penser à un bug.
    doc.setDrawColor(200, 200, 200);
    doc.rect(14, y, CONTENU, 30);
    doc.setFontSize(8);
    doc.setTextColor(150, 150, 150);
    doc.text(
      'Pas assez de ressentis formateur renseignés pour tracer une courbe (' + ressentis.length + ' / ' + mesPassages.length + ' passages renseignés).',
      18, y + 15, { maxWidth: CONTENU - 8 }
    );
    doc.setTextColor(30, 30, 30);
  }
  y += 42;

  // ---------- Page suivante : retours par passage (APP à proposer / commentaires) ----------
  doc.addPage();
  _pdfEnTete(doc, 'Retours par mise en situation', s.prenom + ' ' + s.nom);
  const lignesApp = mesPassages.map(p => {
    const ev = mesEvals(p.id);
    return [p.numero, p.jour, p.sujet || '—', ev?.commentaire || '—', ev?.app1 || '—', ev?.app2 || '—', ev?.app3 || '—'];
  });
  doc.autoTable({
    startY: 28,
    head: [['MSP n°', 'Jour', 'Sujet', 'Commentaire', 'APP 1', 'APP 2', 'APP 3']],
    body: lignesApp,
    styles: { fontSize: 7, cellPadding: 1.5 },
    headStyles: { fillColor: ROUGE_SDIS },
  });

  _pdfPiedDePage(doc);
  doc.save(`Livret_certification_${s.nom}_${s.prenom}.pdf`.replace(/\s+/g, '_'));
  toast('Livret de certification généré');
}

// ---------- Chevalet de formation (livrable 8) ----------
// Une page A4 portrait par stagiaire, à imprimer puis plier en deux (ligne de pliure au milieu
// de la page, matérialisée par un trait pointillé) :
//  - moitié basse (à l'endroit une fois plié posé sur la table) : écusson + prénom NOM + CIS.
//  - moitié haute (tournée à 180°, pour se lire à l'endroit une fois le chevalet plié et posé
//    debout comme un marque-place) : un QR code unique menant à la page d'accueil de l'application
//    (le stagiaire se connecte ensuite avec les identifiants qui lui sont fournis par ailleurs,
//    code de session ou compte personnel — le QR ne fait qu'ouvrir l'appli, pas de connexion
//    automatique) + le chronogramme de la semaine (Jour × Matin/Après-midi). Le chronogramme n'est imprimé que pour les
//    formations de 7 jours maximum ; au-delà, un renvoi invite à consulter l'appli (le chevalet
//    étant une pièce imprimée à l'avance, un programme sur 8 jours+ ne tiendrait plus lisiblement
//    dessus, et les stagiaires ont de toute façon accès au chronogramme complet dans l'appli,
//    onglet Chronogramme côté encadrement / bloc « Programme de la semaine » côté stagiaire).
//
// Technique de rotation à 180° : jsPDF ne fait pas tourner du texte facilement ; on dessine donc
// tout le contenu de la moitié haute sur un <canvas> hors écran, avec un repère translate(w,h) +
// rotate(π) — le contenu est dessiné normalement (coordonnées habituelles, haut-gauche vers
// bas-droite) mais ressort à 180° dans le buffer de pixels final. On insère ensuite cette unique
// image dans le PDF (doc.addImage), ce qui évite de manipuler l'API de rotation de texte/image
// de jsPDF pièce par pièce.
function _pdfDessinerQR(ctx, x, y, taille, donnees) {
  if (typeof qrcode !== 'function') return; // librairie qrcode-generator non chargée
  const qr = qrcode(0, 'M');
  qr.addData(donnees);
  qr.make();
  const n = qr.getModuleCount();
  const cell = taille / n;
  ctx.fillStyle = '#fff';
  ctx.fillRect(x, y, taille, taille);
  ctx.fillStyle = '#1a1a1a';
  for (let r = 0; r < n; r++) {
    for (let c = 0; c < n; c++) {
      if (qr.isDark(r, c)) ctx.fillRect(x + c * cell, y + r * cell, cell + 0.5, cell + 0.5);
    }
  }
}

// Dessine la moitié haute (QR + chronogramme) sur un canvas hors écran, retourné à 180°, et
// renvoie son dataURL PNG prêt à insérer dans le PDF via doc.addImage.
function _pdfCanvasHautChevalet(s, urlApp) {
  const ECH = 4; // px/mm — résolution suffisante pour une impression nette
  const wMM = 210, hMM = 148.5;
  const canvas = document.createElement('canvas');
  canvas.width = wMM * ECH;
  canvas.height = hMM * ECH;
  const ctx = canvas.getContext('2d');
  ctx.fillStyle = '#fff';
  ctx.fillRect(0, 0, canvas.width, canvas.height);
  ctx.translate(canvas.width, canvas.height);
  ctx.rotate(Math.PI);
  const mm = v => v * ECH; // helper : mm → px dans le repère déjà transformé

  // Bandeau rouge SDIS
  ctx.fillStyle = 'rgb(' + ROUGE_SDIS.join(',') + ')';
  ctx.fillRect(0, 0, canvas.width, mm(14));
  ctx.fillStyle = '#fff';
  ctx.font = 'bold ' + mm(6) + 'px Arial';
  ctx.textBaseline = 'middle';
  ctx.fillText('Chronogramme de la semaine', mm(8), mm(7));

  // QR code, en haut à droite du bloc (à gauche une fois retourné à 180°)
  const qrTaille = mm(30);
  const qrX = canvas.width - qrTaille - mm(8);
  const qrY = mm(20);
  _pdfDessinerQR(ctx, qrX, qrY, qrTaille, urlApp);
  ctx.fillStyle = '#333';
  ctx.font = mm(2.6) + 'px Arial';
  ctx.textAlign = 'center';
  ctx.fillText('Scanne pour te connecter', qrX + qrTaille / 2, qrY + qrTaille + mm(4));
  ctx.fillText('à l\'application', qrX + qrTaille / 2, qrY + qrTaille + mm(7.5));
  ctx.textAlign = 'left';

  // Chronogramme (Jour × Matin/Après-midi), limité à 7 jours imprimés
  const nbJours = (S.formation && S.formation.nb_jours) || 5;
  const joursTous = Array.from({ length: nbJours }, (_, i) => 'J' + (i + 1));
  const joursAffiches = joursTous.slice(0, 7);
  const zoneX = mm(8), zoneY = mm(20), zoneW = canvas.width - qrTaille - mm(24), zoneH = mm(100);
  const jourISP = (S.session && S.session.jour_isp) ? 'J' + S.session.jour_isp : null;

  if (nbJours > 7) {
    ctx.fillStyle = '#666';
    ctx.font = mm(3) + 'px Arial';
    ctx.fillText('Formation de ' + nbJours + ' jours :', zoneX, zoneY + mm(8));
    ctx.fillText('chronogramme complet à consulter', zoneX, zoneY + mm(14));
    ctx.fillText('dans l\'application (onglet Chronogramme).', zoneX, zoneY + mm(20));
  } else {
    const colW = zoneW / joursAffiches.length;
    const rowH = zoneH / 2.6;
    ctx.strokeStyle = '#ccc';
    ctx.lineWidth = mm(0.15);
    // en-têtes jours
    ctx.font = 'bold ' + mm(3) + 'px Arial';
    ctx.fillStyle = '#c8102e';
    ctx.textAlign = 'center';
    joursAffiches.forEach((j, i) => ctx.fillText(j + (j === jourISP ? ' 🩺' : ''), zoneX + i * colW + colW / 2, zoneY + mm(3)));
    ctx.textAlign = 'left';
    ['matin', 'apres_midi'].forEach((demi, ri) => {
      const rowY = zoneY + mm(6) + ri * rowH;
      ctx.fillStyle = '#888';
      ctx.font = mm(2.4) + 'px Arial';
      const libDemi = (typeof HORAIRES_DEMI === 'object' && HORAIRES_DEMI)
        ? (demi === 'matin' ? 'MATIN (' + HORAIRES_DEMI.matin + ')' : 'APRÈS-MIDI (' + HORAIRES_DEMI.apres_midi + ')')
        : (demi === 'matin' ? 'MATIN' : 'APRÈS-MIDI');
      ctx.fillText(libDemi, zoneX, rowY - mm(1));
      joursAffiches.forEach((j, ci) => {
        const cellX = zoneX + ci * colW, cellY = rowY;
        if (j === jourISP) {
          ctx.fillStyle = '#e2f5e5';
          ctx.fillRect(cellX, cellY, colW - mm(1), rowH - mm(2));
        }
        ctx.strokeRect(cellX, cellY, colW - mm(1), rowH - mm(2));
        const blocs = (typeof _blocsPlanningCellule === 'function') ? _blocsPlanningCellule(j, demi) : [];
        ctx.fillStyle = '#222';
        ctx.font = mm(2.3) + 'px Arial';
        blocs.slice(0, 4).forEach((b, bi) => {
          const suffixe = (b.duree_minutes && typeof _formatDuree === 'function') ? ' (' + _formatDuree(b.duree_minutes) + ')' : '';
          ctx.fillText(String(b.libelle).slice(0, 20) + suffixe, cellX + mm(1), cellY + mm(3.2) + bi * mm(3.4), colW - mm(2));
        });
      });
    });
  }

  ctx.setTransform(1, 0, 0, 1, 0, 0); // reset avant toDataURL (bonne pratique, sans effet ici)
  return canvas.toDataURL('image/png');
}

async function genererChevalets() {
  if (!window.jspdf) return toast('Bibliothèque PDF non chargée', false);
  if (typeof qrcode !== 'function') return toast('Bibliothèque QR code non chargée (réuploader index.html)', false);
  const stagiaires = S.data.stagiaires;
  if (!stagiaires || !stagiaires.length) return toast('Aucun stagiaire dans cette session', false);
  toast('Génération des chevalets en cours…');

  const { jsPDF } = window.jspdf;
  const doc = new jsPDF({ orientation: 'portrait', unit: 'mm', format: 'a4' });
  // Le QR mène simplement à la page d'accueil de l'app (pas de code en clair dans l'URL) : le
  // stagiaire se connecte ensuite avec le code de session ou son compte personnel, fourni à part.
  const urlBase = location.origin + location.pathname;
  const hMM = 148.5, wMM = 210;

  for (let i = 0; i < stagiaires.length; i++) {
    const s = stagiaires[i];
    if (i > 0) doc.addPage();

    // Moitié haute : QR + chronogramme, rendue à 180° via canvas hors écran
    const imgHaut = _pdfCanvasHautChevalet(s, urlBase);
    doc.addImage(imgHaut, 'PNG', 0, 0, wMM, hMM);

    // Ligne de pliure
    doc.setDrawColor(180, 180, 180);
    doc.setLineDashPattern([2, 1.5], 0);
    doc.line(0, hMM, wMM, hMM);
    doc.setLineDashPattern([], 0);
    doc.setFontSize(7);
    doc.setTextColor(150, 150, 150);
    doc.text('✂ plier ici', wMM / 2, hMM - 2, { align: 'center' });

    // Moitié basse : écusson + identité, à l'endroit
    const lw = 15.4, lh = 24;
    try { doc.addImage(LOGO_SDIS29, 'PNG', (wMM - lw) / 2, hMM + 14, lw, lh); } catch (e) { /* logo optionnel */ }
    doc.setTextColor(30, 30, 30);
    doc.setFontSize(22);
    doc.text((s.prenom + ' ' + s.nom).toUpperCase(), wMM / 2, hMM + 14 + lh + 14, { align: 'center' });
    doc.setFontSize(13);
    doc.setTextColor(100, 100, 100);
    doc.text(s.cis || S.session.lieu || '', wMM / 2, hMM + 14 + lh + 24, { align: 'center' });
  }

  _pdfPiedDePage(doc);
  doc.save(`Chevalets_${(S.session.lieu || S.formation.libelle || 'session')}.pdf`.replace(/\s+/g, '_'));
  toast(`${stagiaires.length} chevalet(s) généré(s)`);
}
